#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int minIndex = 0;
    for(int i = 1; i < n; i++) if(nums[i] < nums[minIndex]) minIndex = i;
    cout << minIndex;
}
